// Script: generar_27_ayuda_contextual_prevencion.js
// Que hace: agrega un sistema de ayuda contextual en Prevencion, con un
// icono de interrogacion (?) junto al titulo "Salud preventiva" que, al
// tocarlo, muestra una vineta explicando que se puede hacer en la
// pestana actual, con la voz de Chiqui preguntando por la mascota del
// tutor.
//
//   1) components/AyudaChiqui.tsx (ARCHIVO NUEVO) -- componente
//      reutilizable: un boton circular con "?" que al tocarlo despliega
//      una burbuja con el texto, y se cierra al tocar fuera o tocar de
//      nuevo el icono.
//
//   2) app/prevencion/page.tsx (REEMPLAZA el existente) -- el icono de
//      ayuda ahora aparece junto al titulo, y el texto que muestra
//      cambia automaticamente segun la pestana activa (Peso, Vacunas,
//      Antiparasitarios, Medicamentos, Enfermedades, Observaciones,
//      Examenes), cada una con su propia explicacion breve.
//
// Como correrlo: node generar_27_ayuda_contextual_prevencion.js
// Confirma "OK" para ambos archivos

const fs = require('fs');
const path = require('path');

function escribir(relPath, b64) {
  const filePath = path.join(...relPath.split('/'));
  const content = Buffer.from(b64, 'base64').toString('utf8');
  const dir = path.dirname(filePath);
  if (!fs.existsSync(dir)) fs.mkdirSync(dir, { recursive: true });
  fs.writeFileSync(filePath, content, 'utf8');
  console.log('OK: ' + filePath);
}

escribir('components/AyudaChiqui.tsx', "");
escribir('app/prevencion/page.tsx', "");
